import LarkCircularRegular from './LarkCircular-Regular.woff2';
import LarkCircularMedium from './LarkCircular-Medium.woff2';
import LarkCircularSemiBold from './LarkCircular-Semibold.woff2';
import LarkCircularBold from './LarkCircular-Bold.woff2';

const isWindows = function () {
  return /windows|win32/i.test(navigator.userAgent);
};

const regularFontFace = new FontFace('Lark Circular', `url(${LarkCircularRegular})`, {
  weight: '400',
});

const mediumFontFace = new FontFace('Lark Circular', `url(${LarkCircularMedium})`, {
  weight: '500',
});

const semiBoldFontFace = new FontFace('Lark Circular', `url(${LarkCircularSemiBold})`, {
  weight: '600',
});

const boldFontFace = new FontFace('Lark Circular', `url(${LarkCircularBold})`, {
  weight: '700',
});

const windowsFontFaces = [regularFontFace, boldFontFace];
const macFontFaces = [regularFontFace, mediumFontFace, semiBoldFontFace];

(isWindows() ? windowsFontFaces : macFontFaces).forEach(font => {
  font.load().then(() => {
    document.fonts.add(font);
  });
});
